     5→/**
     6→ * Vite plugin that updates og:image and twitter:image meta tags
     7→ * to point to the app's opengraph image with the correct Replit domain.
     8→ */
     9→export function metaImagesPlugin(): Plugin {
    10→  return {
    11→    name: 'vite-plugin-meta-images',
    12→    transformIndexHtml(html) {
    13→      const baseUrl = getDeploymentUrl();
    14→      if (!baseUrl) {
    15→        log('[meta-images] no Replit deployment domain found, skipping meta tag updates');
    16→        return html;
    17→      }
    18→
    19→      // Check if opengraph image exists in public directory
    20→      const publicDir = path.resolve(process.cwd(), 'client', 'public');
    21→      const opengraphPngPath = path.join(publicDir, 'opengraph.png');
    22→      const opengraphJpgPath = path.join(publicDir, 'opengraph.jpg');
    23→      const opengraphJpegPath = path.join(publicDir, 'opengraph.jpeg');
    24→
    25→      let imageExt: string | null = null;
    26→      if (fs.existsSync(opengraphPngPath)) {
    27→        imageExt = 'png';
    28→      } else if (fs.existsSync(opengraphJpgPath)) {
    29→        imageExt = 'jpg';
    30→      } else if (fs.existsSync(opengraphJpegPath)) {
    31→        imageExt = 'jpeg';
    32→      }
    33→
    34→      if (!imageExt) {
    35→        log('[meta-images] OpenGraph image not found, skipping meta tag updates');
    36→        return html;
    37→      }
    38→
    39→      const imageUrl = `${baseUrl}/opengraph.${imageExt}`;
    40→
    41→      log('[meta-images] updating meta image tags to:', imageUrl);
    42→
    43→      html = html.replace(
    44→        /<meta\s+property="og:image"\s+content="[^"]*"\s*\/>/g,
    45→        `<meta property="og:image" content="${imageUrl}" />`
    46→      );
    47→
    48→      html = html.replace(
    49→        /<meta\s+name="twitter:image"\s+content="[^"]*"\s*\/>/g,
    50→        `<meta name="twitter:image" content="${imageUrl}" />`
    51→      );
    52→
    53→      return html;
    54→    },
    55→  };
    56→}
    57→
    58→function getDeploymentUrl(): string | null {
    59→  if (process.env.REPLIT_INTERNAL_APP_DOMAIN) {
    60→    const url = `https://${process.env.REPLIT_INTERNAL_APP_DOMAIN}`;
    61→    log('[meta-images] using internal app domain:', url);
    62→    return url;
    63→  }
    64→
    65→  if (process.env.REPLIT_DEV_DOMAIN) {
    66→    const url = `https://${process.env.REPLIT_DEV_DOMAIN}`;
    67→    log('[meta-images] using dev domain:', url);
    68→    return url;
    69→  }
    70→
    71→  return null;
    72→}
