    90→
    91→// ─── G.711 μ-law Codec (pure JS — no external dependencies) ──────────────────
    92→
    93→const MULAW_BIAS = 33;
    94→const MULAW_CLIP = 32635;
    95→
    96→/** Encode one 16-bit PCM sample to a μ-law byte */
    97→export function encodeMulaw(sample: number): number {
    98→  let sign = 0;
    99→  if (sample < 0) { sign = 0x80; sample = -sample; }
   100→  if (sample > MULAW_CLIP) sample = MULAW_CLIP;
   101→  sample += MULAW_BIAS;
   102→  let exp = 7;
   103→  for (let mask = 0x4000; !(sample & mask) && exp > 0; mask >>= 1) exp--;
   104→  const mantissa = (sample >> (exp + 3)) & 0x0f;
   105→  return (~(sign | (exp << 4) | mantissa)) & 0xff;
   106→}
   107→
   108→/** Decode one μ-law byte to a 16-bit PCM sample */
   109→export function decodeMulaw(mulaw: number): number {
   110→  mulaw = ~mulaw;
   111→  const sign     = mulaw & 0x80;
   112→  const exponent = (mulaw >> 4) & 0x07;
   113→  const mantissa = mulaw & 0x0f;
   114→  let sample = ((mantissa << 3) + 132) << exponent;
   115→  sample -= 132;
   116→  return sign ? -sample : sample;
   117→}
   118→
   119→/** Buffer of μ-law bytes → Int16Array of PCM samples */
   120→export function mulawToInt16(buf: Buffer): Int16Array {
   121→  const out = new Int16Array(buf.length);
   122→  for (let i = 0; i < buf.length; i++) out[i] = decodeMulaw(buf[i]);
   123→  return out;
   124→}
   125→
   126→/** Int16Array of PCM samples → Buffer of μ-law bytes */
   127→export function int16ToMulaw(pcm: Int16Array): Buffer {
   128→  const out = Buffer.allocUnsafe(pcm.length);
   129→  for (let i = 0; i < pcm.length; i++) out[i] = encodeMulaw(pcm[i]);
   130→  return out;
   131→}
   132→
   133→// ─── PCM Resampler (linear interpolation) ────────────────────────────────────
   134→
   135→/**
   136→ * Resample PCM16 samples from srcRate to dstRate.
   137→ * Uses linear interpolation — works cleanly for integer ratio pairs (24000→8000, 8000→16000).
   138→ *
   139→ * TODO: Replace with a higher-quality resampler (e.g. libsamplerate via WASM)
   140→ *       if audio artefacts are noticeable in production calls.
   141→ */
   142→export function resamplePCM16(
   143→  samples: Int16Array,
   144→  srcRate: number,
   145→  dstRate: number
   146→): Int16Array {
   147→  if (srcRate === dstRate) return samples;
   148→  const ratio     = srcRate / dstRate;
   149→  const outLength = Math.floor(samples.length / ratio);
   150→  const out       = new Int16Array(outLength);
   151→  for (let i = 0; i < outLength; i++) {
   152→    const pos  = i * ratio;
   153→    const lo   = Math.floor(pos);
   154→    const hi   = Math.min(lo + 1, samples.length - 1);
   155→    const frac = pos - lo;
   156→    out[i]     = Math.round(samples[lo] * (1 - frac) + samples[hi] * frac);
   157→  }
   158→  return out;
   159→}
