   166→  const buf       = Buffer.allocUnsafe(44 + dataBytes);
   167→  buf.write("RIFF", 0);
   168→  buf.writeUInt32LE(36 + dataBytes, 4);
   169→  buf.write("WAVE", 8);
   170→  buf.write("fmt ", 12);
   171→  buf.writeUInt32LE(16, 16);
   172→  buf.writeUInt16LE(1, 20);                          // PCM
   173→  buf.writeUInt16LE(channels, 22);
   174→  buf.writeUInt32LE(sampleRate, 24);
   175→  buf.writeUInt32LE(sampleRate * channels * 2, 28);  // ByteRate
   176→  buf.writeUInt16LE(channels * 2, 32);               // BlockAlign
   177→  buf.writeUInt16LE(16, 34);                         // BitsPerSample
   178→  buf.write("data", 36);
