   227→ *         - ElevenLabs streaming with ULAW_8000 output format
   228→ *         - Deepgram Aura (outputs μ-law on request)
   229→ */
   230→const EXOTEL_SAMPLE_RATE = 8000;
   231→const EXOTEL_CHUNK_BYTES = 320; // 40 ms chunks
