   237→export async function encodeReplyForExotel(text: string): Promise<string[]> {
   238→  // Request raw PCM from OpenAI TTS (24 kHz, 16-bit LE mono, no container)
   239→  const response = await openai.audio.speech.create({
   240→    model:           "tts-1",
   241→    voice:           "nova",
   242→    input:           text,
   243→    response_format: "pcm",
   244→  });
   245→
   246→  const raw      = Buffer.from(await response.arrayBuffer());
   247→  const pcm24k   = new Int16Array(raw.buffer, raw.byteOffset, raw.byteLength / 2);
   248→  const pcm8k    = resamplePCM16(pcm24k, 24000, EXOTEL_SAMPLE_RATE);
   249→  const mulawBuf = int16ToMulaw(pcm8k);
