   251→  // Split into fixed-size chunks and base64-encode each
   252→  const chunks: string[] = [];
   253→  for (let off = 0; off < mulawBuf.length; off += EXOTEL_CHUNK_BYTES) {
   254→    chunks.push(mulawBuf.slice(off, off + EXOTEL_CHUNK_BYTES).toString("base64"));
