   259→// ─── Exotel WebSocket Send Helpers ───────────────────────────────────────────
   260→
   261→/** Send one μ-law audio chunk back to Exotel as a Media event */
   262→export function sendExotelMedia(ws: WebSocket, streamSid: string, payload: string): void {
   263→  if (ws.readyState !== WebSocket.OPEN) return;
