   275→/** Load campaign from DB by ID, fall back to first available if not found */
   276→export async function loadCampaignData(campaignId?: string): Promise<CampaignData> {
   277→  let campaign: any = campaignId ? await storage.getCampaign(campaignId) : null;
   278→  if (!campaign)    campaign = await storage.getAnyCampaign();
   279→  if (!campaign)    return { goal: "sales" };
   280→
