   291→}
   292→
   293→// ─── Per-connection Session ───────────────────────────────────────────────────
   294→
   295→interface ExotelSession {
   296→  streamSid:           string;
   297→  campaignId?:         string;
   298→  mediaChunks:         Buffer[];
   299→  conversationHistory: ConversationMessage[];
   300→  silenceTimer:        ReturnType<typeof setTimeout> | null;
   301→  processing:          boolean;
   302→}
   303→
   304→// Process audio after this many ms of silence from the caller
   305→const SILENCE_TIMEOUT_MS = 1500;
   306→
   307→async function processAudio(ws: WebSocket, session: ExotelSession): Promise<void> {
   308→  if (session.processing || session.mediaChunks.length === 0) return;
   309→  session.processing = true;
   310→
   311→  // Snapshot and clear the buffer so new audio can accumulate during processing
   312→  const chunks        = session.mediaChunks.splice(0);
   313→
   314→  try {
   315→    // 1. Transcribe caller audio
   316→    const userText = await transcribeAudio(chunks);
   317→    log(`[exotel:${session.streamSid}] STT → "${userText}"`, "ws");
   318→    if (!userText) return;
   319→
   320→    // 2. Get AI reply
   321→    const campaignData = await loadCampaignData(session.campaignId);
   322→    session.conversationHistory.push({ role: "user", content: userText });
   323→
   324→    const { reply } = await generateAIResponse(
   325→      session.conversationHistory,
   326→      userText,
   327→      campaignData
   328→    );
   329→
   330→    session.conversationHistory.push({ role: "assistant", content: reply });
   331→    log(`[exotel:${session.streamSid}] AI → "${reply}"`, "ws");
   332→
   333→    // 3. Encode reply to μ-law chunks
   334→    const audioChunks = await encodeReplyForExotel(reply);
   335→
   336→    // 4. Clear Exotel's buffer, then stream reply audio
   337→    sendExotelClear(ws, session.streamSid);
   338→    for (const chunk of audioChunks) {
   339→      sendExotelMedia(ws, session.streamSid, chunk);
   340→    }
   341→    log(`[exotel:${session.streamSid}] Sent ${audioChunks.length} audio chunks`, "ws");
   342→
   343→  } catch (err: any) {
   344→    log(`[exotel:${session.streamSid}] Processing error: ${err.message}`, "ws");
   345→  } finally {
   346→    session.processing = false;
   347→  }
   348→}
   349→
   350→// ─── Main Handler ─────────────────────────────────────────────────────────────
   351→
   352→/**
   353→ * Handle the full lifecycle of one Exotel bidirectional voicebot stream.
   354→ * Wire this to the /exotel-stream WebSocket path in wsServer.ts.
   355→ *
   356→ * @param ws          The raw WebSocket connection from Exotel
   357→ * @param clientIp    Caller IP for logging
   358→ * @param campaignId  Optional — pulled from URL query param ?campaignId=...
   359→ */
   360→export function handleExotelStream(
   361→  ws: WebSocket,
   362→  clientIp: string,
   363→  campaignId?: string
   364→): void {
   365→  const session: ExotelSession = {
   366→    streamSid:           "",
   367→    campaignId,
   368→    mediaChunks:         [],
   369→    conversationHistory: [],
   370→    silenceTimer:        null,
   371→    processing:          false,
   372→  };
   373→
   374→  ws.on("message", async (data) => {
   375→    const raw   = data.toString();
   376→    const event = parseExotelEvent(raw);
   377→
   378→    if (!event) {
   379→      log(`[exotel:${clientIp}] Unparseable: ${raw.slice(0, 120)}`, "ws");
   380→      return;
   381→    }
   382→
   383→    switch (event.event) {
   384→
   385→      case "connected":
   386→        log(`[exotel:${clientIp}] Connected — protocol=${event.protocol} version=${event.version}`, "ws");
   387→        break;
   388→
   389→      case "start":
   390→        session.streamSid = event.start.streamSid;
   391→        if (!session.campaignId) session.campaignId = campaignId;
   392→        log(
   393→          `[exotel:${session.streamSid}] Start — callSid=${event.start.callSid} ` +
   394→          `encoding=${event.start.mediaFormat.encoding} sampleRate=${event.start.mediaFormat.sampleRate}`,
   395→          "ws"
   396→        );
   397→        break;
   398→
   399→      case "media":
   400→        // Only buffer inbound (caller) audio
   401→        if (event.media.track !== "inbound") break;
   402→        session.mediaChunks.push(Buffer.from(event.media.payload, "base64"));
   403→
   404→        // Restart silence timer every time a new chunk arrives
   405→        if (session.silenceTimer) clearTimeout(session.silenceTimer);
   406→        session.silenceTimer = setTimeout(() => {
   407→          processAudio(ws, session);
   408→        }, SILENCE_TIMEOUT_MS);
   409→        break;
   410→
   411→      case "dtmf":
   412→        log(`[exotel:${session.streamSid}] DTMF digit="${event.dtmf.digit}"`, "ws");
   413→        break;
   414→
   415→      case "stop":
   416→        log(`[exotel:${session.streamSid}] Stop — callSid=${event.stop.callSid}`, "ws");
   417→        if (session.silenceTimer) clearTimeout(session.silenceTimer);
   418→        await processAudio(ws, session);
   419→        break;
   420→    }
   421→  });
   422→
   423→  ws.on("close", () => {
   424→    if (session.silenceTimer) clearTimeout(session.silenceTimer);
   425→    log(`[exotel:${session.streamSid || clientIp}] Connection closed`, "ws");
   426→  });
   427→
   428→  ws.on("error", (err) => {
   429→    log(`[exotel:${session.streamSid || clientIp}] Error: ${err.message}`, "ws");
   430→  });
   431→}
