   191→ *   /exotel-stream — μ-law 8 kHz bidirectional voicebot stream for Exotel
   192→ *                    optional query param: ?campaignId=<id>
   193→ */
   194→export function setupWebSocketServer(httpServer: Server): void {
   195→  // /stream — text + MP3 debug path
   196→  const streamWss = new WebSocketServer({ noServer: true });
   197→  streamWss.on("connection", (ws, req) => {
   198→    const clientIp = req.socket.remoteAddress ?? "unknown";
   199→    log(`[/stream] Client connected [${clientIp}]  total=${streamWss.clients.size}`, "ws");
   200→    attachStreamHandlers(streamWss, ws, clientIp);
   201→  });
   202→
   203→  // /exotel-stream — Exotel voicebot path
   204→  const exotelWss = new WebSocketServer({ noServer: true });
   205→  exotelWss.on("connection", (ws, req) => {
   206→    const clientIp = req.socket.remoteAddress ?? "unknown";
   207→    let campaignId: string | undefined;
   208→    try {
   209→      const url  = new URL(req.url ?? "", `ws://${req.headers.host}`);
   210→      campaignId = url.searchParams.get("campaignId") ?? undefined;
   211→    } catch { /* ignore */ }
   212→
   213→    log(`[/exotel-stream] Connection from [${clientIp}] campaignId=${campaignId ?? "none"}  total=${exotelWss.clients.size}`, "ws");
   214→    handleExotelStream(ws, clientIp, campaignId);
   215→  });
   216→
   217→  // Single upgrade router — routes by pathname, passes unknown paths through
   218→  httpServer.on("upgrade", (req, socket, head) => {
   219→    let pathname = "/";
   220→    try {
   221→      pathname = new URL(req.url ?? "", `ws://${req.headers.host}`).pathname;
   222→    } catch { /* ignore */ }
   223→
   224→    if (pathname === "/stream") {
   225→      streamWss.handleUpgrade(req, socket as any, head, (ws) => {
   226→        streamWss.emit("connection", ws, req);
   227→      });
   228→    } else if (pathname === "/exotel-stream") {
   229→      exotelWss.handleUpgrade(req, socket as any, head, (ws) => {
   230→        exotelWss.emit("connection", ws, req);
   231→      });
   232→    }
   233→    // All other paths (e.g. Vite HMR) are left untouched
   234→  });
   235→
   236→  log("WebSocket server ready on path /stream", "ws");
   237→  log("Exotel voicebot stream ready on path /exotel-stream", "ws");
   238→}
