// ─── Exotel Event Types ───────────────────────────────────────────────────────

export interface ExotelConnectedEvent {
  event: "connected";
  protocol: string;
  version: string;
}

export interface ExotelStartEvent {
  event: "start";
  sequenceNumber: string;
  streamSid: string;
  start: {
    streamSid: string;
    accountSid: string;
    callSid: string;
    tracks: string[];
    mediaFormat: {
      encoding: string;   // "audio/x-mulaw"
      sampleRate: number; // 8000
      channels: number;   // 1
    };
  };
}

export interface ExotelMediaEvent {
  event: "media";
  sequenceNumber: string;
  streamSid: string;
  media: {
    track: string;    // "inbound" | "outbound"
    chunk: string;
    timestamp: string;
    payload: string;  // base64-encoded μ-law audio
  };
}

export interface ExotelDTMFEvent {
  event: "dtmf";
  streamSid: string;
  dtmf: { digit: string };
}

export interface ExotelStopEvent {
  event: "stop";
  sequenceNumber: string;
  streamSid: string;
  stop: { accountSid: string; callSid: string };
}

export type ExotelEvent =
  | ExotelConnectedEvent
  | ExotelStartEvent
  | ExotelMediaEvent
  | ExotelDTMFEvent
  | ExotelStopEvent;

// ─── Parse ────────────────────────────────────────────────────────────────────

/**
 * Parse a raw WebSocket message into a typed Exotel event.
 * Returns null if the message is not valid JSON or has no `event` field.
 */
export function parseExotelEvent(raw: string): ExotelEvent | null {
  try {
    const parsed = JSON.parse(raw);
    return parsed?.event ? (parsed as ExotelEvent) : null;
  } catch {
    return null;
  }
}

