// ─── Per-connection Session ───────────────────────────────────────────────────

interface ExotelSession {
  streamSid:           string;
  campaignId?:         string;
  mediaChunks:         Buffer[];
  conversationHistory: ConversationMessage[];
  silenceTimer:        ReturnType<typeof setTimeout> | null;
  processing:          boolean;
}

// Process audio after this many ms of silence from the caller
const SILENCE_TIMEOUT_MS = 1500;

async function processAudio(ws: WebSocket, session: ExotelSession): Promise<void> {
  if (session.processing || session.mediaChunks.length === 0) return;
  session.processing = true;

  // Snapshot and clear the buffer so new audio can accumulate during processing
  const chunks        = session.mediaChunks.splice(0);

  try {
    // 1. Transcribe caller audio
    const userText = await transcribeAudio(chunks);
    log(`[exotel:${session.streamSid}] STT → "${userText}"`, "ws");
    if (!userText) return;

    // 2. Get AI reply
    const campaignData = await loadCampaignData(session.campaignId);
    session.conversationHistory.push({ role: "user", content: userText });

    const { reply } = await generateAIResponse(
      session.conversationHistory,
      userText,
      campaignData
    );

    session.conversationHistory.push({ role: "assistant", content: reply });
    log(`[exotel:${session.streamSid}] AI → "${reply}"`, "ws");

    // 3. Encode reply to μ-law chunks
    const audioChunks = await encodeReplyForExotel(reply);

    // 4. Clear Exotel's buffer, then stream reply audio
    sendExotelClear(ws, session.streamSid);
    for (const chunk of audioChunks) {
      sendExotelMedia(ws, session.streamSid, chunk);
    }
    log(`[exotel:${session.streamSid}] Sent ${audioChunks.length} audio chunks`, "ws");

  } catch (err: any) {
    log(`[exotel:${session.streamSid}] Processing error: ${err.message}`, "ws");
  } finally {
    session.processing = false;
  }
}

// ─── Main Handler ─────────────────────────────────────────────────────────────

/**
 * Handle the full lifecycle of one Exotel bidirectional voicebot stream.
 * Wire this to the /exotel-stream WebSocket path in wsServer.ts.
 *
 * @param ws          The raw WebSocket connection from Exotel
 * @param clientIp    Caller IP for logging
 * @param campaignId  Optional — pulled from URL query param ?campaignId=...
 */
export function handleExotelStream(
  ws: WebSocket,
  clientIp: string,
  campaignId?: string
): void {
  const session: ExotelSession = {
    streamSid:           "",
    campaignId,
    mediaChunks:         [],
    conversationHistory: [],
    silenceTimer:        null,
    processing:          false,
  };

  ws.on("message", async (data) => {
    const raw   = data.toString();
    const event = parseExotelEvent(raw);

    if (!event) {
      log(`[exotel:${clientIp}] Unparseable: ${raw.slice(0, 120)}`, "ws");
      return;
    }

    switch (event.event) {

      case "connected":
        log(`[exotel:${clientIp}] Connected — protocol=${event.protocol} version=${event.version}`, "ws");
        break;

      case "start":
        session.streamSid = event.start.streamSid;
        if (!session.campaignId) session.campaignId = campaignId;
        log(
          `[exotel:${session.streamSid}] Start — callSid=${event.start.callSid} ` +
          `encoding=${event.start.mediaFormat.encoding} sampleRate=${event.start.mediaFormat.sampleRate}`,
          "ws"
        );
        break;

      case "media":
        // Only buffer inbound (caller) audio
        if (event.media.track !== "inbound") break;
        session.mediaChunks.push(Buffer.from(event.media.payload, "base64"));

        // Restart silence timer every time a new chunk arrives
        if (session.silenceTimer) clearTimeout(session.silenceTimer);
        session.silenceTimer = setTimeout(() => {
          processAudio(ws, session);
        }, SILENCE_TIMEOUT_MS);
        break;

      case "dtmf":
        log(`[exotel:${session.streamSid}] DTMF digit="${event.dtmf.digit}"`, "ws");
        break;

      case "stop":
        log(`[exotel:${session.streamSid}] Stop — callSid=${event.stop.callSid}`, "ws");
        if (session.silenceTimer) clearTimeout(session.silenceTimer);
        await processAudio(ws, session);
        break;
    }
  });

  ws.on("close", () => {
    if (session.silenceTimer) clearTimeout(session.silenceTimer);
    log(`[exotel:${session.streamSid || clientIp}] Connection closed`, "ws");
  });

  ws.on("error", (err) => {
    log(`[exotel:${session.streamSid || clientIp}] Error: ${err.message}`, "ws");
  });
}

