async function processAudio(ws: WebSocket, session: ExotelSession): Promise<void> {
  if (session.processing || session.mediaChunks.length === 0) return;
  session.processing = true;

  // Snapshot and clear the buffer so new audio can accumulate during processing
  const chunks    = session.mediaChunks.splice(0);
  const totalBytes = chunks.reduce((s, b) => s + b.length, 0);
  log(`[exotel:${session.streamSid}] ▶ processAudio — ${chunks.length} chunks, ${totalBytes} bytes`, "ws");

  try {
    // 1. Transcribe caller audio via Whisper
    log(`[exotel:${session.streamSid}] ▶ Transcription starting…`, "ws");
    const userText = await transcribeAudio(chunks);
    log(`[exotel:${session.streamSid}] ▶ Transcription result: "${userText}"`, "ws");
    if (!userText) {
      log(`[exotel:${session.streamSid}] ▶ Empty transcription — skipping AI step`, "ws");
      return;
    }

    // 2. Generate AI reply
    const campaignData = await loadCampaignData(session.campaignId);
    session.conversationHistory.push({ role: "user", content: userText });

    const { reply } = await generateAIResponse(
      session.conversationHistory,
      userText,
      campaignData
    );

    session.conversationHistory.push({ role: "assistant", content: reply });
    log(`[exotel:${session.streamSid}] ▶ AI response: "${reply}"`, "ws");

    // 3. Convert reply to μ-law audio chunks via TTS
    const audioChunks = await encodeReplyForExotel(reply);
    log(`[exotel:${session.streamSid}] ▶ TTS encoded — ${audioChunks.length} chunks ready`, "ws");

    // 4. Cancel any buffered Exotel audio, then stream the reply
    sendExotelClear(ws, session.streamSid);
    for (const chunk of audioChunks) {
      sendExotelMedia(ws, session.streamSid, chunk);
    }
    log(`[exotel:${session.streamSid}] ▶ Audio response sent to Exotel — ${audioChunks.length} chunks`, "ws");

  } catch (err: any) {
    log(`[exotel:${session.streamSid}] ✖ Processing error: ${err.message}`, "ws");
  } finally {
    session.processing = false;
  }
}

