```typescript
export async function encodeReplyForExotel(text: string): Promise<string[]> {
  // Request raw PCM from OpenAI TTS (24 kHz, 16-bit LE mono, no container)
  const response = await openai.audio.speech.create({
    model:           "tts-1",
    voice:           "nova",
    input:           text,
    response_format: "pcm",
  });

  const raw      = Buffer.from(await response.arrayBuffer());
  const pcm24k   = new Int16Array(raw.buffer, raw.byteOffset, raw.byteLength / 2);
  const pcm8k    = resamplePCM16(pcm24k, 24000, EXOTEL_SAMPLE_RATE);
  const mulawBuf = int16ToMulaw(pcm8k);

  // Split into fixed-size chunks and base64-encode each
  const chunks: string[] = [];
  for (let off = 0; off < mulawBuf.length; off += EXOTEL_CHUNK_BYTES) {
    chunks.push(mulawBuf.slice(off, off + EXOTEL_CHUNK_BYTES).toString("base64"));
  }
  return chunks;
}
```

