// Real payload from logs: "CAAIAAgACAAIAAgACAAIAAgACAAIAAgACAAIAAgACAA="
const buf = Buffer.from("CAAIAAgACAAIAAgACAAIAAgACAAIAAgACAAIAAgACAA=", "base64");

console.log("Raw bytes (hex):", buf.toString("hex").slice(0, 64));
console.log("Byte values:", [...buf.slice(0, 20)]);

// Interpret as PCM16 LE (signed 16-bit little-endian)
const pcm16 = [];
for (let i = 0; i < Math.min(buf.length, 20); i += 2) {
  pcm16.push(buf.readInt16LE(i));
}
console.log("As PCM16 LE values:", pcm16);

// Interpret as μ-law bytes
function decodeMulaw(b) {
  b = ~b;
  const sign = b & 0x80;
  const exp = (b >> 4) & 0x07;
  const mant = b & 0x0f;
  let s = ((mant << 3) + 132) << exp;
  s -= 132;
  return sign ? -s : s;
}
const mulaw = [...buf.slice(0, 10)].map(decodeMulaw);
console.log("As μ-law decoded values:", mulaw);

console.log("\nConclusion: PCM16 LE near-zero values = silence. μ-law gives large values = NOT μ-law.");

