// Fire transcription this many ms after the last VOICED chunk (caller pause)
const SILENCE_TIMEOUT_MS = 600;
// Fallback: force transcription this many ms after the first chunk in a window
const FORCE_PROCESS_MS = 2000;
// RMS energy threshold — chunks below this are treated as silence/background noise
// Exotel streams continuously even during silence (flat PCM), so without this
// the silence timer would be reset by every silent chunk and never fire.
const VAD_THRESHOLD = 300;

/** Calculate RMS energy of a PCM16 LE buffer — used for voice activity detection */
function rmsLevel(buf: Buffer): number {
  if (buf.length < 2) return 0;
  let sumSq = 0;
  for (let i = 0; i + 1 < buf.length; i += 2) {
    const sample = buf.readInt16LE(i);
    sumSq += sample * sample;
  }
  return Math.sqrt(sumSq / (buf.length / 2));
}

