// ── Silence timer: fires after 1500 ms of no new audio ─────────────
// Restarted on every chunk so it only fires when the caller actually
// pauses speaking.
if (session.silenceTimer) clearTimeout(session.silenceTimer);
session.silenceTimer = setTimeout(() => {
  log(`[exotel:${session.streamSid}] silence detected (${SILENCE_TIMEOUT_MS}ms) — triggering transcription`, "ws");
  if (session.forceTimer) { clearTimeout(session.forceTimer); session.forceTimer = null; }
  session.firstChunkAt = null;
  processAudio(ws, session);
}, SILENCE_TIMEOUT_MS);

// ── Force timer: fires 3 s after the FIRST chunk in this window ────
// Exotel streams continuously even during silence (encoded as flat
// PCM), so the silence timer alone may never fire.  This guarantees
// transcription is triggered at least every FORCE_PROCESS_MS.
if (!session.firstChunkAt) {
  session.firstChunkAt = Date.now();
  session.forceTimer = setTimeout(() => {
    log(`[exotel:${session.streamSid}] force-process after ${FORCE_PROCESS_MS}ms — silence timer did not fire`, "ws");
    if (session.silenceTimer) { clearTimeout(session.silenceTimer); session.silenceTimer = null; }
    session.firstChunkAt = null;
    session.forceTimer = null;
    processAudio(ws, session);
  }, FORCE_PROCESS_MS);
}

