// ── VAD silence timer: only resets on voiced chunks ────────────────
// Exotel streams flat PCM even during silence, so we use energy-based
// VAD to avoid resetting the timer on every silent chunk.
const rms = rmsLevel(audioBuf);
log(`[exotel:${session.streamSid}] chunk RMS=${rms.toFixed(0)}`, "ws");

if (rms > VAD_THRESHOLD) {
  // Voiced chunk — reset the silence countdown
  if (session.silenceTimer) clearTimeout(session.silenceTimer);
  session.silenceTimer = setTimeout(() => {
    log(`[exotel:${session.streamSid}] end-of-speech detected (${SILENCE_TIMEOUT_MS}ms) — triggering transcription`, "ws");
    if (session.forceTimer) { clearTimeout(session.forceTimer); session.forceTimer = null; }
    session.firstChunkAt = null;
    processAudio(ws, session);
  }, SILENCE_TIMEOUT_MS);
}

// ── Force timer: fires FORCE_PROCESS_MS after the FIRST chunk ───────
// Fallback in case VAD never sees voice (very quiet speaker, etc.)
if (!session.firstChunkAt) {
  session.firstChunkAt = Date.now();
  session.forceTimer = setTimeout(() => {
    log(`[exotel:${session.streamSid}] force-process after ${FORCE_PROCESS_MS}ms — fallback trigger`, "ws");
    if (session.silenceTimer) { clearTimeout(session.silenceTimer); session.silenceTimer = null; }
    session.firstChunkAt = null;
    session.forceTimer = null;
    processAudio(ws, session);
  }, FORCE_PROCESS_MS);
}

