import axios from "axios";

const EXOTEL_SID       = process.env.EXOTEL_SID       || "nijvox1";
const EXOTEL_API_KEY   = process.env.EXOTEL_API_KEY   || "a6d6fc20da41f7bf3be9c45cbc74df118faba5983c56b290";
const EXOTEL_API_TOKEN = process.env.EXOTEL_API_TOKEN || "9ec44c27c506218f06d46d2dee4af0d05fdaf714955e3b87";

export interface ExotelCallResult {
  success: boolean;
  data?: any;
  error?: string;
}

const EXOTEL_PHONE = process.env.EXOTEL_PHONE || "+918047359287";
const PUBLIC_URL   = process.env.PUBLIC_URL   || "https://nijvox.com";

export async function makeExotelCall(
  toNumber: string,
  campaignId?: string
): Promise<ExotelCallResult> {
  console.log("Calling number:", toNumber, "campaignId:", campaignId || "none");

  const url = `https://api.exotel.com/v1/Accounts/${EXOTEL_SID}/Calls/connect`;

  // Point directly to our /exotel/voice webhook so we control the ExoML response.
  // campaignId is embedded as a query param so /exotel/voice can pass it to the Stream URL.
  const voiceWebhook = campaignId
    ? `${PUBLIC_URL}/exotel/voice?campaignId=${encodeURIComponent(campaignId)}`
    : `${PUBLIC_URL}/exotel/voice`;

  const params = new URLSearchParams();
  params.append("From",     toNumber);       // Customer number
  params.append("CallerId", EXOTEL_PHONE);   // Exophone / caller ID
  params.append("Url",      voiceWebhook);   // Our dynamic ExoML webhook

  console.log("CUSTOMER =",  toNumber);
  console.log("CALLERID =",  EXOTEL_PHONE);
  console.log("VOICE URL =", voiceWebhook);

  try {
    const response = await axios.post(url, params, {
      auth: {
        username: EXOTEL_API_KEY,
        password: EXOTEL_API_TOKEN,
      },
    });

    console.log("[Exotel] Call response:", JSON.stringify(response.data));
    return { success: true, data: response.data };
  } catch (error: any) {
    const errMsg = error.response?.data || error.message || "Unknown error";
    console.error("[Exotel] Call failed:", errMsg);
    return { success: false, error: JSON.stringify(errMsg) };
  }
}

